import requests

# RabbitMQ server details
RABBITMQ_URL = 'http://localhost:15672'
USERNAME = 'admin'
PASSWORD = 'password'

def create_vhost(vhost_name):
    url = f'{RABBITMQ_URL}/api/vhosts/{vhost_name}'
    headers = {'Content-Type': 'application/json'}
    payload = {
        "name": vhost_name,
        "tracing": False
    }
    response = requests.put(url, auth=(USERNAME, PASSWORD), headers=headers, json=payload)
    if response.status_code == 201:
        print(f'Vhost {vhost_name} created successfully.')
    else:
        print(f'Failed to create vhost {vhost_name}. Status code: {response.status_code}')

def set_user_permissions(vhost_name, username):
    url = f'{RABBITMQ_URL}/api/permissions/{vhost_name}/{username}'
    headers = {'Content-Type': 'application/json'}
    payload = {
        "configure": ".*",
        "write": ".*",
        "read": ".*"
    }
    response = requests.put(url, auth=(USERNAME, PASSWORD), headers=headers, json=payload)
    if response.status_code == 201:
        print(f'Permissions for {username} on vhost {vhost_name} set successfully.')
    else:
        print(f'Failed to set permissions for {username} on vhost {vhost_name}. Status code: {response.status_code}')

# Example usage
create_vhost('app1')
set_user_permissions('app1', 'user1')

create_vhost('app2')
set_user_permissions('app2', 'user2')